enum NFCPushTarget {
  TAG,
  PEER,
  ANY
};

enum NFCWatchMode {
  WEBNFC_ONLY,
  ANY
};

struct NFCError {
  NFCErrorType error_type;
};

struct NFCRecord {
  NFCRecordType recordType;
  string? mediaType;
  array<uint8> data;
};

struct NFCMessage {
  array<NFCRecord> data;
  string? url;
};

struct NFCPushOptions {
  NFCPushTarget target;
  double timeout;
  bool ignoreRead;
};

struct NFCRecordTypeFilter {
  NFCRecordType recordType;
};

struct NFCWatchOptions {
  string? url;
  NFCRecordTypeFilter? recordFilter;
  string? mediaType;
